        else:
            super().do_GET()

    def log_message(self, format, *args):
        pass  # Suppress logs


if __name__ == "__main__":
    server = HTTPServer(("0.0.0.0", 8765), StatsHandler)
    print("Dashboard running at http://localhost:8765/")
    server.serve_forever()

